// Cálculo de juros compostos com retiradas customizadas
// Inputs (todos opcionais, defaults = 0)
// valorInicial, aporteMensal, valorRetirada (number)
// taxa (number, %), taxaUnit: 'anual' | 'mensal'
// periodo (number), periodoUnit: 'anos' | 'meses'
// numRetiradas (int >= 0)
// retiradaFreq: 'mensal' | 'anual' (frequência das retiradas)
//
// Modelo: regime composto, aporte e retirada no INÍCIO de cada mês,
// taxa convertida para mensal: i_m = (1+i_a)^(1/12) - 1 quando anual.
// Retiradas: a 1ª retirada acontece no mês 1 (ou ano 1) e segue a frequência
// definida, totalizando "numRetiradas" saques (limitado ao período).

export function calcular({
  valorInicial = 0,
  aporteMensal = 0,
  taxa = 0,
  taxaUnit = "anual",
  periodo = 0,
  periodoUnit = "anos",
  valorRetirada = 0,
  numRetiradas = 0,
  retiradaFreq = "mensal",
  ir = 0, // alíquota de imposto de renda em % sobre os juros
}) {
  const meses = Math.max(0, Math.round(periodoUnit === "anos" ? periodo * 12 : periodo));
  const taxaMensal =
    taxaUnit === "anual" ? Math.pow(1 + taxa / 100, 1 / 12) - 1 : taxa / 100;

  const stepRetirada = retiradaFreq === "anual" ? 12 : 1;
  const maxSaques = Math.max(0, Math.floor(numRetiradas));

  let saldo = Number(valorInicial) || 0;
  let totalInvestido = Number(valorInicial) || 0;
  let totalRetirado = 0;
  let saquesFeitos = 0;

  const linha = [
    {
      mes: 0,
      ano: 0,
      saldo,
      investido: totalInvestido,
      juros: 0,
      retirado: 0,
    },
  ];

  for (let m = 1; m <= meses; m++) {
    // Aporte no início do mês
    saldo += Number(aporteMensal) || 0;
    totalInvestido += Number(aporteMensal) || 0;

    // Retirada no início do mês (conforme frequência)
    if (saquesFeitos < maxSaques) {
      const aplicaRetirada =
        retiradaFreq === "mensal" ? true : (m - 1) % stepRetirada === 0;
      if (aplicaRetirada && valorRetirada > 0) {
        const v = Math.min(saldo, Number(valorRetirada));
        saldo -= v;
        totalRetirado += v;
        saquesFeitos += 1;
      }
    }

    // Rendimento do mês
    const rendimento = saldo * taxaMensal;
    saldo += rendimento;

    linha.push({
      mes: m,
      ano: Math.ceil(m / 12),
      saldo,
      investido: totalInvestido,
      juros: saldo - totalInvestido + totalRetirado,
      retirado: totalRetirado,
    });
  }

  const final = linha[linha.length - 1];
  const totalJuros = final.saldo - final.investido + final.retirado;
  const aliquota = Math.max(0, Number(ir) || 0) / 100;
  const imposto = totalJuros > 0 ? totalJuros * aliquota : 0;
  const montanteLiquido = final.saldo - imposto;

  return {
    meses,
    taxaMensalEfetiva: taxaMensal,
    montanteFinal: final.saldo,
    montanteLiquido,
    totalInvestido: final.investido,
    totalJuros,
    totalRetirado: final.retirado,
    imposto,
    aliquotaIR: aliquota,
    saquesFeitos,
    linhaTempo: linha,
  };
}

// Formatação BRL
export function formatBRL(value) {
  const n = Number.isFinite(value) ? value : 0;
  return new Intl.NumberFormat("pt-BR", {
    style: "currency",
    currency: "BRL",
    minimumFractionDigits: 2,
    maximumFractionDigits: 2,
  }).format(n);
}

// Para inputs com máscara BRL
export function parseBRLInput(str) {
  if (!str) return 0;
  const clean = String(str).replace(/[^\d,.-]/g, "").replace(/\./g, "").replace(",", ".");
  const n = parseFloat(clean);
  return Number.isFinite(n) ? n : 0;
}

export function maskBRL(rawDigits) {
  // Recebe apenas dígitos, retorna string formatada (ex: 1234567 -> "12.345,67")
  const digits = String(rawDigits).replace(/\D/g, "");
  if (!digits) return "";
  const padded = digits.padStart(3, "0");
  const intPart = padded.slice(0, -2).replace(/^0+(?=\d)/, "");
  const decPart = padded.slice(-2);
  const intFormatted = (intPart || "0").replace(/\B(?=(\d{3})+(?!\d))/g, ".");
  return `${intFormatted},${decPart}`;
}
