import React from "react";
import { maskBRL } from "@/lib/calc";

// Campo numérico genérico (sem máscara) - usado para taxa, período, n° retiradas
export function NumberField({
  id,
  label,
  value,
  onChange,
  placeholder = "0",
  suffix,
  icon: Icon,
  step = "any",
  min = 0,
  testid,
}) {
  return (
    <div data-testid={`${testid}-wrapper`}>
      <label htmlFor={id} className="field-label">
        {label}
      </label>
      <div className="relative">
        {Icon && (
          <div className="absolute left-4 top-1/2 -translate-y-1/2 text-purple-400/80 pointer-events-none">
            <Icon size={18} strokeWidth={1.75} />
          </div>
        )}
        <input
          id={id}
          data-testid={testid}
          type="number"
          inputMode="decimal"
          className="num-input"
          placeholder={placeholder}
          value={value}
          step={step}
          min={min}
          onChange={(e) => onChange(e.target.value)}
        />
        {suffix && (
          <div className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-400 text-sm font-medium pointer-events-none">
            {suffix}
          </div>
        )}
      </div>
    </div>
  );
}


export function CurrencyField({
  id,
  label,
  value,        // string formatada visível
  onChange,     // recebe string formatada
  icon: Icon,
  placeholder = "0,00",
  testid,
}) {
  const handle = (e) => {
    const digits = e.target.value.replace(/\D/g, "");
    onChange(maskBRL(digits));
  };
  return (
    <div data-testid={`${testid}-wrapper`}>
      <label htmlFor={id} className="field-label">
        {label}
      </label>
      <div className="relative">
        <div className="absolute left-4 top-1/2 -translate-y-1/2 text-purple-400/90 text-sm font-semibold pointer-events-none flex items-center gap-2">
          {Icon && <Icon size={16} strokeWidth={1.75} />}
          <span>R$</span>
        </div>
        <input
          id={id}
          data-testid={testid}
          type="text"
          inputMode="numeric"
          className="num-input"
          style={{ paddingLeft: "4.5rem" }}
          placeholder={placeholder}
          value={value}
          onChange={handle}
        />
      </div>
    </div>
  );
}

// Toggle segmentado (ex: anual/mensal)
export function SegmentedToggle({ options, value, onChange, testid }) {
  return (
    <div className="seg-group" data-testid={testid}>
      {options.map((opt) => (
        <button
          key={opt.value}
          type="button"
          data-testid={`${testid}-${opt.value}`}
          className={`seg-btn ${value === opt.value ? "active" : ""}`}
          onClick={() => onChange(opt.value)}
        >
          {opt.label}
        </button>
      ))}
    </div>
  );
}
