import React, { useMemo, useState, useRef, useEffect } from "react";
import { motion, AnimatePresence } from "framer-motion";
import {
  Calculator,
  Coins,
  TrendingUp,
  Percent,
  Calendar,
  Banknote,
  Hash,
  Sparkles,
  RotateCcw,
  Wallet,
  ArrowDownToLine,
  Receipt,
  ShieldCheck,
} from "lucide-react";
import { CurrencyField, NumberField, SegmentedToggle } from "@/components/Fields";
import ResultChart from "@/components/ResultChart";
import MonthlyTable from "@/components/MonthlyTable";
import { calcular, formatBRL, parseBRLInput } from "@/lib/calc";

const initialState = {
  valorInicial: "",
  aporteMensal: "",
  taxa: "",
  taxaUnit: "anual",
  periodo: "",
  periodoUnit: "anos",
  valorRetirada: "",
  numRetiradas: "",
  retiradaFreq: "mensal",
};

export default function App() {
  const [form, setForm] = useState(initialState);
  const [result, setResult] = useState(null);
  const [isOffline, setIsOffline] = useState(
    typeof navigator !== "undefined" ? !navigator.onLine : false
  );
  const resultRef = useRef(null);

  useEffect(() => {
    const on = () => setIsOffline(false);
    const off = () => setIsOffline(true);
    window.addEventListener("online", on);
    window.addEventListener("offline", off);
    return () => {
      window.removeEventListener("online", on);
      window.removeEventListener("offline", off);
    };
  }, []);

  const setField = (k) => (v) => setForm((s) => ({ ...s, [k]: v }));

  const onCalcular = () => {
    const payload = {
      valorInicial: parseBRLInput(form.valorInicial),
      aporteMensal: parseBRLInput(form.aporteMensal),
      taxa: Number(form.taxa) || 0,
      taxaUnit: form.taxaUnit,
      periodo: Number(form.periodo) || 0,
      periodoUnit: form.periodoUnit,
      valorRetirada: parseBRLInput(form.valorRetirada),
      numRetiradas: Number(form.numRetiradas) || 0,
      retiradaFreq: form.retiradaFreq,
      ir: Number(form.ir) || 0,
    };
    const r = calcular(payload);
    setResult(r);
  };

  useEffect(() => {
    if (result && resultRef.current) {
      resultRef.current.scrollIntoView({ behavior: "smooth", block: "start" });
    }
  }, [result]);

  const onLimpar = () => {
    setForm(initialState);
    setResult(null);
  };

  const canCalc = useMemo(() => {
    return Number(form.periodo) > 0 && Number(form.taxa) >= 0;
  }, [form.periodo, form.taxa]);

  return (
    <div className="min-h-screen w-full text-slate-100">
      <div className="mx-auto w-full max-w-md px-5 pt-12 pb-32">
        {/* Offline badge */}
        {isOffline && (
          <motion.div
            initial={{ opacity: 0, y: -10 }}
            animate={{ opacity: 1, y: 0 }}
            className="mb-4 flex items-center gap-2 px-3 py-2 rounded-full bg-emerald-500/10 border border-emerald-400/20 text-emerald-300 text-[11px] w-fit mx-auto"
            data-testid="offline-badge"
          >
            <span className="w-1.5 h-1.5 rounded-full bg-emerald-400 animate-pulse" />
            Modo offline — funcionando normalmente
          </motion.div>
        )}

        {/* Header */}
        <motion.header
          initial={{ opacity: 0, y: -8 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.4 }}
          className="mb-8"
          data-testid="app-header"
        >
          <div className="flex flex-col items-center text-center">
            <motion.img
              src="/carlos-invest-logo.png"
              alt="Carlos Invest"
              className="w-32 h-32 rounded-3xl mb-4 select-none"
              style={{
                boxShadow:
                  "0 20px 60px -20px rgba(147,51,234,0.7), 0 0 0 1px rgba(168,85,247,0.25)",
              }}
              initial={{ scale: 0.9, opacity: 0 }}
              animate={{ scale: 1, opacity: 1 }}
              transition={{ duration: 0.5, ease: "easeOut" }}
              draggable={false}
              data-testid="app-logo"
            />
            <div className="text-[10px] uppercase tracking-[0.35em] text-purple-300/80 font-display mb-1">
              faça seu dinheiro crescer
            </div>
            <h1 className="font-display text-2xl font-light tracking-tight">
              Calculadora <span className="font-medium text-purple-300">do Carlos</span>
            </h1>
            <p className="text-sm text-slate-400 leading-relaxed mt-3 max-w-[280px]">
              Simule seus juros compostos com aportes e retiradas programadas.
            </p>
          </div>
        </motion.header>

        {/* Form */}
        <motion.section
          initial={{ opacity: 0, y: 16 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.5, delay: 0.05 }}
          className="glass-card p-5 space-y-5"
          data-testid="form-card"
        >
          <CurrencyField
            id="valorInicial"
            label="Valor inicial"
            value={form.valorInicial}
            onChange={setField("valorInicial")}
            icon={Wallet}
            testid="input-valor-inicial"
          />

          <CurrencyField
            id="aporteMensal"
            label="Aporte mensal"
            value={form.aporteMensal}
            onChange={setField("aporteMensal")}
            icon={Coins}
            testid="input-aporte-mensal"
          />

          <div>
            <div className="flex items-end justify-between mb-2">
              <label className="field-label mb-0">Taxa de juros</label>
              <SegmentedToggle
                options={[
                  { value: "anual", label: "Anual" },
                  { value: "mensal", label: "Mensal" },
                ]}
                value={form.taxaUnit}
                onChange={setField("taxaUnit")}
                testid="toggle-taxa-unit"
              />
            </div>
            <NumberField
              id="taxa"
              label=""
              value={form.taxa}
              onChange={setField("taxa")}
              icon={Percent}
              suffix="%"
              placeholder="0"
              step="0.01"
              testid="input-taxa"
            />
          </div>

          <div>
            <div className="flex items-end justify-between mb-2">
              <label className="field-label mb-0">Período</label>
              <SegmentedToggle
                options={[
                  { value: "anos", label: "Anos" },
                  { value: "meses", label: "Meses" },
                ]}
                value={form.periodoUnit}
                onChange={setField("periodoUnit")}
                testid="toggle-periodo-unit"
              />
            </div>
            <NumberField
              id="periodo"
              label=""
              value={form.periodo}
              onChange={setField("periodo")}
              icon={Calendar}
              suffix={form.periodoUnit}
              placeholder="0"
              step="1"
              testid="input-periodo"
            />
          </div>

          {/* Bloco de retiradas (feature extra do Carlos) */}
          <div className="pt-2 mt-2 border-t border-white/5">
            <div className="flex items-center gap-2 mb-4">
              <ArrowDownToLine size={14} className="text-purple-300" />
              <span className="text-[11px] uppercase tracking-[0.22em] text-purple-300/90 font-display font-semibold">
                Retiradas programadas
              </span>
              <span className="ml-auto text-[10px] text-slate-500 italic">opcional</span>
            </div>

            <div className="space-y-5">
              <CurrencyField
                id="valorRetirada"
                label="Valor de retirada"
                value={form.valorRetirada}
                onChange={setField("valorRetirada")}
                icon={Banknote}
                testid="input-valor-retirada"
              />

              <div>
                <div className="flex items-end justify-between mb-2">
                  <label className="field-label mb-0">Quantas vezes</label>
                  <SegmentedToggle
                    options={[
                      { value: "mensal", label: "Mensal" },
                      { value: "anual", label: "Anual" },
                    ]}
                    value={form.retiradaFreq}
                    onChange={setField("retiradaFreq")}
                    testid="toggle-retirada-freq"
                  />
                </div>
                <NumberField
                  id="numRetiradas"
                  label=""
                  value={form.numRetiradas}
                  onChange={setField("numRetiradas")}
                  icon={Hash}
                  suffix={`x ${form.retiradaFreq === "anual" ? "por ano" : "por mês"}`}
                  placeholder="0"
                  step="1"
                  testid="input-num-retiradas"
                />
              </div>
            </div>
          </div>

          {/* Bloco Imposto de Renda */}
          <div className="pt-2 mt-2 border-t border-white/5">
            <div className="flex items-center gap-2 mb-4">
              <Receipt size={14} className="text-purple-300" />
              <span className="text-[11px] uppercase tracking-[0.22em] text-purple-300/90 font-display font-semibold">
                Imposto de Renda
              </span>
              <span className="ml-auto text-[10px] text-slate-500 italic">incide sobre os juros</span>
            </div>
            <NumberField
              id="ir"
              label=""
              value={form.ir}
              onChange={setField("ir")}
              icon={Percent}
              suffix="%"
              placeholder="Ex: 15"
              step="0.01"
              testid="input-ir"
            />
            <div className="mt-2 text-[10px] text-slate-500 leading-relaxed">
              Tabela regressiva (Renda Fixa): até 180 dias = 22,5% · 181–360 = 20% · 361–720 = 17,5% · acima 720 = 15%.
            </div>
          </div>

          {/* Buttons */}
          <div className="space-y-3 pt-2">
            <button
              type="button"
              data-testid="btn-calcular"
              className="primary-btn flex items-center justify-center gap-2"
              onClick={onCalcular}
              disabled={!canCalc}
              style={!canCalc ? { opacity: 0.55, cursor: "not-allowed" } : {}}
            >
              <Sparkles size={18} strokeWidth={1.8} />
              Calcular
            </button>
            <button
              type="button"
              data-testid="btn-limpar"
              className="ghost-btn flex items-center justify-center gap-2"
              onClick={onLimpar}
            >
              <RotateCcw size={16} />
              Limpar
            </button>
          </div>
        </motion.section>

        {/* Results */}
        <AnimatePresence>
          {result && (
            <motion.section
              ref={resultRef}
              key="result"
              initial={{ opacity: 0, y: 24 }}
              animate={{ opacity: 1, y: 0 }}
              exit={{ opacity: 0, y: 12 }}
              transition={{ duration: 0.5 }}
              className="mt-8 space-y-4"
              data-testid="result-section"
            >
              {/* Highlight Montante Final */}
              <div
                className="rounded-3xl p-6 relative overflow-hidden"
                style={{
                  background:
                    "linear-gradient(135deg, rgba(88,28,135,0.55) 0%, rgba(15,7,28,0.85) 100%)",
                  border: "1px solid rgba(168,85,247,0.25)",
                  boxShadow: "0 30px 60px -25px rgba(147,51,234,0.45)",
                }}
                data-testid="result-highlight"
              >
                <div className="absolute -right-6 -top-6 w-28 h-28 rounded-full bg-purple-500/20 blur-3xl pointer-events-none" />
                <div className="flex items-center gap-2 mb-2 text-purple-200/90">
                  <TrendingUp size={14} />
                  <span className="text-[10px] uppercase tracking-[0.25em] font-semibold">
                    Montante final
                  </span>
                </div>
                <div
                  className="font-display font-medium tracking-tight text-white"
                  style={{ fontSize: "clamp(1.9rem, 8vw, 2.6rem)" }}
                  data-testid="result-montante-final"
                >
                  {formatBRL(result.montanteFinal)}
                </div>
                <div className="mt-2 text-xs text-purple-200/70">
                  ao final de {result.meses} meses ({(result.meses / 12).toFixed(1).replace(".", ",")} anos)
                </div>
              </div>

              {/* Summary trio */}
              <div className="grid grid-cols-3 gap-3">
                <SummaryCard
                  label="Investido"
                  value={result.totalInvestido}
                  color="text-sky-300"
                  testid="result-total-investido"
                />
                <SummaryCard
                  label="Juros"
                  value={result.totalJuros}
                  color="text-emerald-300"
                  testid="result-total-juros"
                />
                <SummaryCard
                  label="Retirado"
                  value={result.totalRetirado}
                  color="text-rose-300"
                  testid="result-total-retirado"
                />
              </div>

              {/* IR + Líquido */}
              {result.imposto > 0 && (
                <div
                  className="rounded-3xl p-5 relative overflow-hidden"
                  style={{
                    background:
                      "linear-gradient(135deg, rgba(15,7,28,0.85) 0%, rgba(76,29,149,0.4) 100%)",
                    border: "1px solid rgba(168,85,247,0.18)",
                  }}
                  data-testid="result-ir-card"
                >
                  <div className="flex items-center justify-between mb-3">
                    <div className="flex items-center gap-2 text-purple-200/90">
                      <Receipt size={14} />
                      <span className="text-[10px] uppercase tracking-[0.22em] font-semibold">
                        IR · {(result.aliquotaIR * 100).toFixed(2).replace(".", ",")}% sobre juros
                      </span>
                    </div>
                    <span
                      className="text-rose-300 font-mono font-medium text-sm"
                      data-testid="result-imposto"
                    >
                      − {formatBRL(result.imposto)}
                    </span>
                  </div>
                  <div className="flex items-end justify-between pt-3 border-t border-white/5">
                    <div className="flex items-center gap-2 text-emerald-200/90">
                      <ShieldCheck size={14} />
                      <span className="text-[10px] uppercase tracking-[0.22em] font-semibold">
                        Montante líquido
                      </span>
                    </div>
                    <div
                      className="font-display font-medium text-emerald-300 tracking-tight"
                      style={{ fontSize: "clamp(1.1rem, 5vw, 1.45rem)" }}
                      data-testid="result-montante-liquido"
                    >
                      {formatBRL(result.montanteLiquido)}
                    </div>
                  </div>
                </div>
              )}

              {/* Chart */}
              <div className="glass-card p-4">
                <div className="px-1 mb-2 flex items-center justify-between">
                  <div className="text-[10px] uppercase tracking-[0.25em] font-semibold text-slate-400">
                    Evolução do patrimônio
                  </div>
                  <div className="text-[10px] text-slate-500 font-mono" data-testid="result-taxa-mensal">
                    {(result.taxaMensalEfetiva * 100).toFixed(3).replace(".", ",")}%/m
                  </div>
                </div>
                <ResultChart data={result.linhaTempo} />
              </div>

              {/* Yearly table */}
              <MonthlyTable data={result.linhaTempo} />

              {/* Retirada info */}
              {result.saquesFeitos > 0 && (
                <div
                  className="glass-card p-4 text-xs text-slate-300 flex items-center gap-2"
                  data-testid="result-retirada-info"
                >
                  <ArrowDownToLine size={14} className="text-rose-300" />
                  <span>
                    {result.saquesFeitos} retirada{result.saquesFeitos > 1 ? "s" : ""}{" "}
                    realizada{result.saquesFeitos > 1 ? "s" : ""} ao longo do período.
                  </span>
                </div>
              )}
            </motion.section>
          )}
        </AnimatePresence>

        {/* Footer */}
        <footer className="mt-10 text-center text-[10px] text-slate-600 tracking-widest uppercase">
          v1.0 · funciona offline
        </footer>
      </div>
    </div>
  );
}

function SummaryCard({ label, value, color, testid }) {
  return (
    <div
      className="glass-card p-4 text-center"
      data-testid={`${testid}-card`}
    >
      <div className="text-[9px] uppercase tracking-[0.18em] text-slate-400 font-semibold mb-1">
        {label}
      </div>
      <div
        className={`font-display font-medium ${color} truncate`}
        style={{ fontSize: "clamp(0.78rem, 3.4vw, 0.95rem)" }}
        data-testid={testid}
        title={formatBRL(value)}
      >
        {formatBRL(value)}
      </div>
    </div>
  );
}
