import React from "react";
import {
  ResponsiveContainer,
  AreaChart,
  Area,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  Legend,
} from "recharts";
import { formatBRL } from "@/lib/calc";

const fmtCompact = (v) => {
  if (Math.abs(v) >= 1_000_000)
    return `R$ ${(v / 1_000_000).toFixed(1).replace(".", ",")}M`;
  if (Math.abs(v) >= 1_000)
    return `R$ ${(v / 1_000).toFixed(0)}k`;
  return `R$ ${Math.round(v)}`;
};

function CustomTooltip({ active, payload, label }) {
  if (!active || !payload?.length) return null;
  return (
    <div
      className="rounded-2xl p-3 text-xs shadow-2xl"
      style={{
        background: "rgba(20, 10, 35, 0.92)",
        backdropFilter: "blur(16px)",
        border: "1px solid rgba(168,85,247,0.25)",
        minWidth: 180,
      }}
      data-testid="chart-tooltip"
    >
      <div className="text-slate-400 mb-2 font-display uppercase tracking-widest">
        Mês {label}
      </div>
      {payload.map((p) => (
        <div key={p.dataKey} className="flex items-center justify-between gap-3 py-0.5">
          <span className="flex items-center gap-2 text-slate-300">
            <span
              className="inline-block w-2 h-2 rounded-full"
              style={{ background: p.color }}
            />
            {p.name}
          </span>
          <span className="font-mono text-white">{formatBRL(p.value)}</span>
        </div>
      ))}
    </div>
  );
}

export default function ResultChart({ data }) {
  // Reduz pontos para charts muito longos (mantém performance e leitura)
  const sample = (() => {
    if (data.length <= 120) return data;
    const step = Math.ceil(data.length / 120);
    return data.filter((_, i) => i % step === 0 || i === data.length - 1);
  })();

  return (
    <div className="w-full h-[260px]" data-testid="result-chart">
      <ResponsiveContainer width="100%" height="100%">
        <AreaChart data={sample} margin={{ top: 10, right: 4, left: -10, bottom: 0 }}>
          <defs>
            <linearGradient id="g-saldo" x1="0" y1="0" x2="0" y2="1">
              <stop offset="0%" stopColor="#A855F7" stopOpacity={0.55} />
              <stop offset="100%" stopColor="#A855F7" stopOpacity={0} />
            </linearGradient>
            <linearGradient id="g-invest" x1="0" y1="0" x2="0" y2="1">
              <stop offset="0%" stopColor="#38BDF8" stopOpacity={0.35} />
              <stop offset="100%" stopColor="#38BDF8" stopOpacity={0} />
            </linearGradient>
            <linearGradient id="g-juros" x1="0" y1="0" x2="0" y2="1">
              <stop offset="0%" stopColor="#10B981" stopOpacity={0.3} />
              <stop offset="100%" stopColor="#10B981" stopOpacity={0} />
            </linearGradient>
          </defs>
          <CartesianGrid stroke="rgba(255,255,255,0.04)" vertical={false} />
          <XAxis
            dataKey="mes"
            tick={{ fill: "rgba(148,163,184,0.6)", fontSize: 10 }}
            stroke="rgba(255,255,255,0.05)"
            tickLine={false}
            interval="preserveStartEnd"
          />
          <YAxis
            tick={{ fill: "rgba(148,163,184,0.6)", fontSize: 10 }}
            stroke="rgba(255,255,255,0.05)"
            tickLine={false}
            tickFormatter={fmtCompact}
            width={60}
          />
          <Tooltip content={<CustomTooltip />} cursor={{ stroke: "rgba(168,85,247,0.4)" }} />
          <Legend
            wrapperStyle={{ fontSize: 11, color: "rgba(226,232,240,0.9)" }}
            iconType="circle"
            iconSize={8}
          />
          <Area
            type="monotone"
            dataKey="saldo"
            name="Montante"
            stroke="#A855F7"
            strokeWidth={2}
            fill="url(#g-saldo)"
          />
          <Area
            type="monotone"
            dataKey="investido"
            name="Investido"
            stroke="#38BDF8"
            strokeWidth={1.5}
            fill="url(#g-invest)"
          />
          <Area
            type="monotone"
            dataKey="juros"
            name="Juros"
            stroke="#10B981"
            strokeWidth={1.5}
            fill="url(#g-juros)"
          />
        </AreaChart>
      </ResponsiveContainer>
    </div>
  );
}
