import React, { useState } from "react";
import { formatBRL } from "@/lib/calc";
import { ChevronDown } from "lucide-react";

export default function MonthlyTable({ data }) {
  const [open, setOpen] = useState(false);

  // Agrupa por ano para visão mais limpa
  const yearly = data
    .filter((d) => d.mes > 0 && d.mes % 12 === 0)
    .map((d) => ({
      ano: d.mes / 12,
      saldo: d.saldo,
      investido: d.investido,
      juros: d.juros,
      retirado: d.retirado,
    }));

  if (yearly.length === 0) return null;

  return (
    <div className="glass-card overflow-hidden" data-testid="yearly-table-card">
      <button
        type="button"
        data-testid="toggle-table-btn"
        onClick={() => setOpen(!open)}
        className="w-full flex items-center justify-between px-5 py-4 text-left"
      >
        <div>
          <div className="text-xs text-slate-400 uppercase tracking-[0.18em] font-semibold">
            Evolução ano a ano
          </div>
          <div className="text-sm text-slate-200 mt-0.5">
            {yearly.length} {yearly.length === 1 ? "ano" : "anos"} de projeção
          </div>
        </div>
        <ChevronDown
          size={20}
          className={`text-purple-300 transition-transform duration-300 ${open ? "rotate-180" : ""}`}
        />
      </button>

      {open && (
        <div className="px-2 pb-4 overflow-x-auto" data-testid="yearly-table-content">
          <table className="w-full text-sm">
            <thead>
              <tr className="text-[10px] uppercase tracking-widest text-slate-500">
                <th className="text-left font-semibold px-3 py-2">Ano</th>
                <th className="text-right font-semibold px-3 py-2">Montante</th>
                <th className="text-right font-semibold px-3 py-2">Investido</th>
                <th className="text-right font-semibold px-3 py-2">Juros</th>
                <th className="text-right font-semibold px-3 py-2">Retirado</th>
              </tr>
            </thead>
            <tbody>
              {yearly.map((row) => (
                <tr
                  key={row.ano}
                  className="border-t border-white/5 text-slate-200"
                  data-testid={`yearly-row-${row.ano}`}
                >
                  <td className="px-3 py-2 font-display font-medium">{row.ano}</td>
                  <td className="px-3 py-2 text-right font-mono">{formatBRL(row.saldo)}</td>
                  <td className="px-3 py-2 text-right font-mono text-sky-300/90">
                    {formatBRL(row.investido)}
                  </td>
                  <td className="px-3 py-2 text-right font-mono text-emerald-300/90">
                    {formatBRL(row.juros)}
                  </td>
                  <td className="px-3 py-2 text-right font-mono text-rose-300/90">
                    {row.retirado > 0 ? formatBRL(row.retirado) : "—"}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
}
